// Load WORLD-NEWS job configuration
const JOB_NAME = 'world-news';

const fs = require('fs');
const path = `/data/jobs/${JOB_NAME}.json`;

try {
  const configData = fs.readFileSync(path, 'utf8');
  const config = JSON.parse(configData);

  // Return one item per source
  const items = config.sources.map(source => ({
    json: {
      config: config,
      source: source,
      jobName: JOB_NAME
    }
  }));

  return items;
} catch (error) {
  throw new Error(`Could not read job config at ${path}: ${error.message}`);
}

// Filter articles by lookback_hours and process
const items = $input.all();
const now = new Date();
const lookbackHours = items[0]?.json?.config?.lookback_hours || 24;
const maxAgeMs = lookbackHours * 60 * 60 * 1000;

const allArticles = [];

for (const item of items) {
  if (!item.json.items) continue;

  const config = item.json.config;
  const source = item.json.source;

  for (const article of item.json.items) {
    const pubDate = new Date(article.pubDate || article.isoDate || Date.now());
    const ageMs = now - pubDate;

    if (ageMs <= maxAgeMs) {
      allArticles.push({
        json: {
          title: article.title || 'Untitled',
          description: article.contentSnippet || article.content || article.summary || '',
          link: article.link || article.guid || '',
          pubDate: pubDate.toISOString(),
          source: source.name,
          category: source.category
        }
      });
    }
  }
}

// Limit to max_articles
const maxArticles = items[0]?.json?.config?.max_articles || 60;
return allArticles.slice(0, maxArticles);

// Build the prompt for Ollama
const items = $input.all();
if (items.length === 0 || !items[0].json.articles || items[0].json.articles.length === 0) {
  return [];
}

const config = items[0].json.config;
const articles = items[0].json.articles;

// Group articles by category
const byCategory = {};
for (const article of articles) {
  const cat = article.json.category || 'general';
  if (!byCategory[cat]) byCategory[cat] = [];
  byCategory[cat].push(article.json);
}

// Build article list
let articleList = '';
for (const [category, catArticles] of Object.entries(byCategory)) {
  articleList += `\n## ${category.toUpperCase()}\n`;
  for (const article of catArticles) {
    articleList += `- **${article.title}** (${article.source}): ${article.description.substring(0, 200)}\n`;
  }
}

const userPrompt = config.user_prompt_format || 'Summarize these news articles:';

return [{
  json: {
    config: config,
    systemPrompt: config.system_prompt || 'You are a news summarizer.',
    userPrompt: userPrompt + articleList,
    articleCount: articles.length
  }
}];

// Format for Discord with env var fallback
const items = $input.all();
const config = items[0]?.json?.config;
const summary = items[0]?.json?.response || 'No summary generated.';

const title = config?.name || 'News Digest';
const today = new Date().toISOString().split('T')[0];

// Get webhook URL - check config first, then env var, then empty
let webhookUrl = config?.discord?.webhook_url || '';
const webhookEnvVar = config?.discord?.webhook_url_env;

// If no webhook in config but env var name specified, try to get from env
if (!webhookUrl && webhookEnvVar && process.env[webhookEnvVar]) {
  webhookUrl = process.env[webhookEnvVar];
}

// Also try TEST_DISCORD_WEBHOOK_URL as fallback for test jobs
if (!webhookUrl && process.env.TEST_DISCORD_WEBHOOK_URL) {
  webhookUrl = process.env.TEST_DISCORD_WEBHOOK_URL;
}

// Split into chunks if needed (Discord limit is 4096)
const MAX_LENGTH = 4000;
const chunks = [];

if (summary.length <= MAX_LENGTH) {
  chunks.push(summary);
} else {
  const parts = summary.split('\n\n');
  let current = '';
  for (const part of parts) {
    if ((current + part).length > MAX_LENGTH) {
      if (current) chunks.push(current.trim());
      current = part;
    } else {
      current += '\n\n' + part;
    }
  }
  if (current) chunks.push(current.trim());
}

const embeds = chunks.map((chunk, i) => ({
  title: i === 0 ? `${title} - ${today}` : `${title} (cont.)`,
  description: chunk,
  color: config?.discord?.embed_color || 3447003,
  footer: {
    text: i === chunks.length - 1 ? `Generated by ${config?.model || 'Ollama'}` : `Part ${i + 1}/${chunks.length}`
  }
}));

// If no webhook URL, return empty to skip Discord sending gracefully
if (!webhookUrl) {
  return [{
    json: {
      skipDiscord: true,
      reason: 'No Discord webhook configured. Set webhook_url in job config or TEST_DISCORD_WEBHOOK_URL in .env',
      summary: summary
    }
  }];
}

return [{
  json: {
    webhookUrl: webhookUrl,
    username: config?.discord?.username || 'World News Bot',
    embeds: embeds,
    skipDiscord: false
  }
}];

// Log that we're skipping Discord
const items = $input.all();
const item = items[0]?.json;

if (item?.skipDiscord) {
  console.log('Skipping Discord:', item.reason);
  return [{
    json: {
      message: 'Discord sending skipped',
      reason: item.reason,
      summary: item.summary
    }
  }];
}

return [];
